#include<stdio.h>
#include<stdlib.h>
unsigned long long int func(unsigned long long int a,unsigned long long int b)
{
	unsigned long long int f=0;
	if(a==0)
		f= b;
	else if(b==0)
		f=a;
	else if(a==1 || b==1)
		f=1;
	else if (a>b)
		f= func(b,a%b);
	else if (a<b)
		f= func(b%a,a);
	else if (a==b)
		f=a;
	return f;
}
int main(void) 
{
	unsigned long long int a,b,x,y;
