use std::io::{self, Read};

fn gcd( aa: u64, bb: u64 ) -> u64 {
    let (mut a,mut b) = if aa > bb {
        (bb,aa)
    } else {
        (aa,bb)
    };

    loop {
        let r = b % a;
        if r == 0 {
            break;
        }
        b = a;
        a = r;
    }
    a
}

fn main() -> () {

    let mut buffer = String::new();
    let stdin = io::stdin();
    let mut handle = stdin.lock();

    handle.read_to_string(&mut buffer).expect("stdin");

    let mut arr : Vec<_> = buffer.split_whitespace().map(|x| x.parse::<i64>().unwrap() ).collect();

    let a = arr[0] as u64;
    let b = arr[1] as u64;
    let mut x = arr[2] as u64;
    let mut y = arr[3] as u64;

    let d = gcd(x,y);

    // println!("d:{}",d);

    x = x / d;
    y = y / d;

    // println!("{},{}",x,y);

    let num_numer = a / x;
    let num_denom = b / y;
    use std::cmp;
    let mm = cmp::min( num_numer, num_denom );
    println!("{}",mm);
}
